class EventEmitter{constructor(){this.eventTarget=new EventTarget}emit(t,e){t=new CustomEvent(String(t),{detail:e});this.eventTarget.dispatchEvent(t)}on(t,e){const n=t=>{t instanceof CustomEvent&&e(t.detail)},r=String(t);return this.eventTarget.addEventListener(r,n),()=>this.eventTarget.removeEventListener(r,n)}once(t,e){const n=this.on(t,(...t)=>{n(),e(...t)});return n}}export default EventEmitter;